CustomField.formula:
/* 1. 특별 Role 우선 */ IF( OR( ISPICKVAL(JobRole__c, "그룹장"), ISPICKVAL(JobRole__c, "팀장") ), CASE( TEXT(JobRole__c), "팀장", 0, "그룹장", 50, 90 ), 1000 )
/* 2. Level 정렬 */ + CASE( TEXT(JobLevel__c), "이사", 100, "영업대표", 200, "책임", 300, 900 )
/* 3. 일반 Role 정렬 */ + IF( OR( ISPICKVAL(JobRole__c, "그룹장"), ISPICKVAL(JobRole__c, "팀장") ), 0, CASE( TEXT(JobRole__c), "Senior Dev", 10, "Dev II", 20, "Dev I", 30, 99 ) )
